contracts/AccessController.sol.content:
// SPDX-License-Identifier: MIT
pragma solidity ^0.8.24;

/// @title AccessController
/// @notice Fine-grained, time-limited, per-record access control with immutable audit log.
/// @dev This is the most critical contract in the system.
///      Key design decisions:
///      - Access is granted BY the owner TO any address (doctor, attorney, auditor, family).
///      - Grants can be scoped to specific record IDs (empty array = all records).
///      - Grants carry a tier (read-only vs write) and an optional expiry.
///      - Every access event is logged immutably on-chain.
///      - The admin can register "verified providers" (doctors, law firms) but
///        the owner decides who gets access — admin cannot override this.
contract AccessController {

    // -------------------------------------------------------------------------
    // Enums
    // -------------------------------------------------------------------------

    /// @dev Tiers are ordered by privilege level (lower index = less access).
    enum AccessTier {
        EMERGENCY_READ,  // 0 — view public emergency card only (no encrypted records)
        RECORD_READ,     // 1 — read specific or all encrypted records
        FULL_READ,       // 2 — read all records + version history + metadata
        PROVIDER_WRITE   // 3 — read + add new versions / clinical/legal annotations
    }

    // -------------------------------------------------------------------------
    // Data structures
    // -------------------------------------------------------------------------

    struct AccessGrant {
        AccessTier tier;
        uint256    grantedAt;
        /// @dev expiresAt == 0 means the grant is permanent until explicitly revoked.
        uint256    expiresAt;
        /// @dev allowedRecordIds: empty array means access to ALL records.
        ///      Populated array restricts to only those specific record IDs.
        uint256[]  allowedRecordIds;
        bool       active;
    }

    struct AccessLog {
        address accessor;
        uint256 recordId;
        uint256 version;
        uint256 timestamp;
        /// @dev Free-form action string: "READ", "DOWNLOAD", "ADD_NOTE", "SHARE", etc.
        string  action;
    }

    // -------------------------------------------------------------------------
    // State
    // -------------------------------------------------------------------------

    /// patient/owner → accessor → grant
    mapping(address => mapping(address => AccessGrant)) private grants;
    /// patient/owner → immutable access log array
    mapping(address => AccessLog[]) private accessLogs;
    /// verified providers registered by admin (optional — owner can grant to any address)
    mapping(address => bool) public registeredProviders;
    address public admin;

    // -------------------------------------------------------------------------
    // Events
    // -------------------------------------------------------------------------

    event AccessGranted(
        address indexed patient,
        address indexed accessor,
        AccessTier      tier,
        uint256         expiresAt
    );
    event AccessRevoked(
        address indexed patient,
        address indexed accessor
    );
    event AccessLogged(
        address indexed patient,
        address indexed accessor,
        uint256         recordId,
        string          action
    );
    event ProviderRegistered(address indexed provider);

    // -------------------------------------------------------------------------
    // Modifiers
    // -------------------------------------------------------------------------

    modifier onlyAdmin() {
        require(msg.sender == admin, "AccessController: not admin");
        _;
    }

    // -------------------------------------------------------------------------
    // Constructor
    // -------------------------------------------------------------------------

    constructor() {
        admin = msg.sender;
    }

    // -------------------------------------------------------------------------
    // Admin functions
    // -------------------------------------------------------------------------

    /// @notice Register a healthcare provider / law firm / verified accessor.
    /// @dev Registration does NOT grant them access to any patient — it only
    ///      marks them as a verified entity that patients can discover and choose.
    function registerProvider(address provider) external onlyAdmin {
        require(provider != address(0), "AccessController: zero address");
        registeredProviders[provider] = true;
        emit ProviderRegistered(provider);
    }

    // -------------------------------------------------------------------------
    // Grant / Revoke (called by the data owner)
    // -------------------------------------------------------------------------

    /// @notice Grant access to any address for a configurable tier and duration.
    /// @param accessor        The address receiving access (doctor, attorney, auditor).
    /// @param tier            Privilege level (see AccessTier enum).
    /// @param durationSeconds How long the grant is valid. 0 = permanent.
    /// @param recordIds       Specific record IDs to allow. Empty = all records.
    function grantAccess(
        address          accessor,
        AccessTier       tier,
        uint256          durationSeconds,
        uint256[] calldata recordIds
    ) external {
        require(accessor != address(0), "AccessController: zero address");
        require(accessor != msg.sender,  "AccessController: cannot grant to self");
        uint256 expiry = durationSeconds == 0
            ? 0
            : block.timestamp + durationSeconds;
        grants[msg.sender][accessor] = AccessGrant({
            tier:             tier,
            grantedAt:        block.timestamp,
            expiresAt:        expiry,
            allowedRecordIds: recordIds,
            active:           true
        });
        emit AccessGranted(msg.sender, accessor, tier, expiry);
    }

    /// @notice Revoke an existing grant immediately.
    function revokeAccess(address accessor) external {
        require(
            grants[msg.sender][accessor].active,
            "AccessController: no active grant to revoke"
        );
        grants[msg.sender][accessor].active = false;
        emit AccessRevoked(msg.sender, accessor);
    }

    // -------------------------------------------------------------------------
    // Access check (read-only, called by frontend before fetching files)
    // -------------------------------------------------------------------------

    /// @notice Check whether `accessor` is currently allowed to access `recordId`
    ///         belonging to `patient`.
    /// @return allowed  True if access is currently valid.
    /// @return tier     The access tier granted (only meaningful when allowed == true).
    function checkAccess(
        address patient,
        address accessor,
        uint256 recordId
    ) external view returns (bool allowed, AccessTier tier) {
        AccessGrant storage g = grants[patient][accessor];

        // Check grant is active
        if (!g.active) return (false, AccessTier.EMERGENCY_READ);

        // Check expiry
        if (g.expiresAt != 0 && block.timestamp > g.expiresAt)
            return (false, AccessTier.EMERGENCY_READ);

        // Check record-level restriction
        if (g.allowedRecordIds.length > 0) {
            bool found = false;
            for (uint256 i = 0; i < g.allowedRecordIds.length; i++) {
                if (g.allowedRecordIds[i] == recordId) {
                    found = true;
                    break;
                }
            }
            if (!found) return (false, AccessTier.EMERGENCY_READ);
        }

        return (true, g.tier);
    }

    // -------------------------------------------------------------------------
    // Audit log (called by frontend / provider after accessing a record)
    // -------------------------------------------------------------------------

    /// @notice Append an access event to the patient's immutable audit log.
    /// @param patient   The owner whose record was accessed.
    /// @param recordId  Which record was accessed.
    /// @param version   Which version was accessed.
    /// @param action    String descriptor: "READ", "DOWNLOAD", "ADD_NOTE", etc.
    function logAccess(
        address patient,
        uint256 recordId,
        uint256 version,
        string calldata action
    ) external {
        // Allow patient to log their own actions too (e.g., self-download)
        require(
            msg.sender == patient || grants[patient][msg.sender].active,
            "AccessController: not authorized to log for this patient"
        );
        accessLogs[patient].push(AccessLog({
            accessor:  msg.sender,
            recordId:  recordId,
            version:   version,
            timestamp: block.timestamp,
            action:    action
        }));
        emit AccessLogged(patient, msg.sender, recordId, action);
    }

    // -------------------------------------------------------------------------
    // Views
    // -------------------------------------------------------------------------

    function getAccessLogs(address patient)
        external
        view
        returns (AccessLog[] memory)
    {
        return accessLogs[patient];
    }

    function getGrant(
        address patient,
        address accessor
    )
        external
        view
        returns (
            AccessTier tier,
            uint256    grantedAt,
            uint256    expiresAt,
            bool       active
        )
    {
        AccessGrant storage g = grants[patient][accessor];
        return (g.tier, g.grantedAt, g.expiresAt, g.active);
    }

    /// @notice Returns true if a grant exists and has not yet expired.
    ///         Does NOT check record-level restrictions.
    function isActiveAccessor(address patient, address accessor)
        external
        view
        returns (bool)
    {
        AccessGrant storage g = grants[patient][accessor];
        if (!g.active) return false;
        if (g.expiresAt != 0 && block.timestamp > g.expiresAt) return false;
        return true;
    }
}

contracts/HealthRecordStore.sol.content:
// SPDX-License-Identifier: MIT
pragma solidity ^0.8.24;

import "./AccessController.sol";

/// @title HealthRecordStore
/// @notice Versioned, typed document storage. Each record is identified by
///         (owner address, recordId) and supports unlimited versions.
/// @dev Integrated with AccessController for on-chain permission enforcement.
///      Owners add records themselves; authorised providers can update records
///      (add new versions) on behalf of a patient if granted PROVIDER_WRITE.
///      All writes automatically emit an immutable audit log entry via
///      AccessController.logAccess — no manual frontend call needed.
contract HealthRecordStore {

    // -------------------------------------------------------------------------
    // Enums
    // -------------------------------------------------------------------------

    enum DocumentType {
        // --- Medical ---
        LAB_REPORT,          // 0
        PRESCRIPTION,        // 1
        IMAGING,             // 2
        DISCHARGE_SUMMARY,   // 3
        VACCINATION,         // 4
        // --- General vault ---
        INSURANCE_POLICY,    // 5
        LEGAL_CONTRACT,      // 6
        IDENTITY_DOCUMENT,   // 7
        FINANCIAL_RECORD,    // 8
        PROPERTY_DOCUMENT,   // 9
        ACADEMIC_CREDENTIAL, // 10
        OTHER                // 11
    }

    enum RecordStatus {
        ACTIVE,
        ARCHIVED,
        DELETED
    }

    // -------------------------------------------------------------------------
    // Data structures
    // -------------------------------------------------------------------------

    struct RecordVersion {
        string  cid;
        string  metadataHash;
        uint256 timestamp;
        address uploadedBy;
        RecordStatus status;
    }

    struct RecordHead {
        DocumentType docType;
        string   title;
        uint256  latestVersion;
        uint256  createdAt;
        bool     exists;
    }

    // -------------------------------------------------------------------------
    // State
    // -------------------------------------------------------------------------

    AccessController private immutable accessController;

    /// owner → recordId → RecordHead
    mapping(address => mapping(uint256 => RecordHead)) private recordHeads;
    /// owner → recordId → version → RecordVersion
    mapping(address => mapping(uint256 => mapping(uint256 => RecordVersion))) private versions;
    /// owner → total record count (also used as next recordId)
    mapping(address => uint256) private recordCounts;

    // -------------------------------------------------------------------------
    // Events
    // -------------------------------------------------------------------------

    event RecordAdded(
        address indexed owner,
        uint256 indexed recordId,
        DocumentType docType,
        string cid
    );
    event RecordUpdated(
        address indexed owner,
        uint256 indexed recordId,
        uint256 newVersion,
        string cid
    );
    event RecordStatusChanged(
        address indexed owner,
        uint256 indexed recordId,
        uint256 version,
        RecordStatus newStatus
    );

    // -------------------------------------------------------------------------
    // Constructor
    // -------------------------------------------------------------------------

    /// @param _accessController Address of the deployed AccessController contract.
    constructor(address _accessController) {
        require(_accessController != address(0), "HealthRecordStore: zero address");
        accessController = AccessController(_accessController);
    }

    // -------------------------------------------------------------------------
    // Internal helpers
    // -------------------------------------------------------------------------

    /// @dev Revert if msg.sender is neither the patient nor holds PROVIDER_WRITE.
    function _requireWriteAccess(address patient, uint256 recordId) internal view {
        if (msg.sender == patient) return; // owner always allowed
        (bool allowed, AccessController.AccessTier tier) =
            accessController.checkAccess(patient, msg.sender, recordId);
        require(
            allowed && tier == AccessController.AccessTier.PROVIDER_WRITE,
            "HealthRecordStore: caller lacks PROVIDER_WRITE access"
        );
    }

    /// @dev Log an access event immutably via AccessController.
    function _log(address patient, uint256 recordId, uint256 version, string memory action) internal {
        // Use try/catch so a logging failure never blocks the main operation.
        try accessController.logAccess(patient, recordId, version, action) {}
        catch {}
    }

    // -------------------------------------------------------------------------
    // Write functions
    // -------------------------------------------------------------------------

    /// @notice Add a brand-new record (version 1). Only the owner can call this.
    function addRecord(
        DocumentType    docType,
        string calldata title,
        string calldata cid,
        string calldata metadataHash
    ) external {
        uint256 id = recordCounts[msg.sender];
        recordHeads[msg.sender][id] = RecordHead({
            docType:       docType,
            title:         title,
            latestVersion: 1,
            createdAt:     block.timestamp,
            exists:        true
        });
        versions[msg.sender][id][1] = RecordVersion({
            cid:          cid,
            metadataHash: metadataHash,
            timestamp:    block.timestamp,
            uploadedBy:   msg.sender,
            status:       RecordStatus.ACTIVE
        });
        recordCounts[msg.sender]++;
        emit RecordAdded(msg.sender, id, docType, cid);
        _log(msg.sender, id, 1, "ADD_RECORD");
    }

    /// @notice Add a new version to an existing record.
    /// @param patient   The owner of the record.
    /// @param recordId  The record to update.
    /// @dev Caller must be the patient OR hold PROVIDER_WRITE in AccessController.
    ///      An immutable audit log entry is created automatically on-chain.
    function updateRecord(
        address patient,
        uint256 recordId,
        string calldata newCid,
        string calldata newMetadataHash
    ) external {
        require(
            recordHeads[patient][recordId].exists,
            "HealthRecordStore: record does not exist"
        );
        _requireWriteAccess(patient, recordId);

        uint256 newVersion = recordHeads[patient][recordId].latestVersion + 1;
        recordHeads[patient][recordId].latestVersion = newVersion;
        versions[patient][recordId][newVersion] = RecordVersion({
            cid:          newCid,
            metadataHash: newMetadataHash,
            timestamp:    block.timestamp,
            uploadedBy:   msg.sender,
            status:       RecordStatus.ACTIVE
        });
        emit RecordUpdated(patient, recordId, newVersion, newCid);
        _log(patient, recordId, newVersion, "UPDATE_RECORD");
    }

    /// @notice Change the status of a specific version (archive or soft-delete).
    /// @param patient  The owner of the record.
    /// @dev Caller must be the patient OR hold PROVIDER_WRITE.
    function setVersionStatus(
        address      patient,
        uint256      recordId,
        uint256      version,
        RecordStatus newStatus
    ) external {
        require(
            recordHeads[patient][recordId].exists,
            "HealthRecordStore: record does not exist"
        );
        _requireWriteAccess(patient, recordId);
        versions[patient][recordId][version].status = newStatus;
        emit RecordStatusChanged(patient, recordId, version, newStatus);
        _log(patient, recordId, version, "SET_STATUS");
    }

    // -------------------------------------------------------------------------
    // View functions
    // -------------------------------------------------------------------------

    function getLatestRecord(address owner, uint256 recordId)
        external
        view
        returns (
            string memory cid,
            string memory metadataHash,
            uint256       timestamp,
            address       uploadedBy
        )
    {
        uint256 v = recordHeads[owner][recordId].latestVersion;
        RecordVersion storage rv = versions[owner][recordId][v];
        return (rv.cid, rv.metadataHash, rv.timestamp, rv.uploadedBy);
    }

    function getVersion(
        address owner,
        uint256 recordId,
        uint256 version
    )
        external
        view
        returns (
            string memory   cid,
            string memory   metadataHash,
            uint256         timestamp,
            address         uploadedBy,
            RecordStatus    status
        )
    {
        RecordVersion storage rv = versions[owner][recordId][version];
        return (rv.cid, rv.metadataHash, rv.timestamp, rv.uploadedBy, rv.status);
    }

    function getRecordHead(address owner, uint256 recordId)
        external
        view
        returns (
            DocumentType docType,
            string memory title,
            uint256 latestVersion,
            uint256 createdAt,
            bool    exists
        )
    {
        RecordHead storage h = recordHeads[owner][recordId];
        return (h.docType, h.title, h.latestVersion, h.createdAt, h.exists);
    }

    function getRecordCount(address owner) external view returns (uint256) {
        return recordCounts[owner];
    }

    /// @notice Returns the address of the wired AccessController.
    function getAccessController() external view returns (address) {
        return address(accessController);
    }
}

